insert into platform_topic_master (subject_slug, topic_slug, page_name, sections)
values
('spanish', 'x-1-listening-and-dictation', 'X.1 Listening and Dictation', '{"learn": {"enabled": true, "items": [{"title": "What does Paper 1 actually test?", "html": "<p>Paper 1 is the <strong>Listening</strong> exam — a <strong>written</strong> paper: you hear a recording and write your answers straight onto the question paper. It is worth <strong>25% of your whole GCSE</strong>.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>Foundation</td><td>35 minutes, 40 marks</td></tr>\n              <tr><td>Higher</td><td>45 minutes, 50 marks</td></tr>\n            </table>\n            <p>You get <strong>5 minutes'' reading time</strong> before the recording starts, and <strong>2 minutes at the end</strong> to check your answers — use both fully. The exam has two sections: <strong>Section A</strong> (comprehension, 32/40 marks) and <strong>Section B</strong> (dictation, 8/10 marks).</p>\n            <p>Vocabulary for talking about the exam itself:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"escuchar\">escuchar</span></td><td>to listen</td><td><span data-say=\"la grabación\">la grabación</span></td><td>the recording</td></tr>\n              <tr><td><span data-say=\"comprender\">comprender</span></td><td>to understand</td><td><span data-say=\"contestar\">contestar</span></td><td>to answer</td></tr>\n            </table>", "check": {"question": "How much reading time do you get before the recording starts in Paper 1?", "options": ["5 minutes", "10 minutes", "No reading time at all — the recording starts immediately", "2 minutes, the same as the checking time at the end"], "answer": 0, "explain": "You get 5 minutes'' reading time before the recording starts, plus a separate 2 minutes at the end to check answers."}}, {"title": "Section A: how to use the reading time", "html": "<p>Section A questions are asked <strong>in English</strong> and answered <strong>in English or non-verbally</strong> (a tick, a letter, a number). Use the 5-minute reading window to read <strong>every</strong> question first, underline the key words, and predict what TYPE of answer each one needs — a number? a reason? an opinion?</p>\n            <p>Once the recording starts, don''t try to translate word by word. Listen for whole known chunks. Example: a recording says <span data-say=\"Normalmente, veo la tele y hago mis deberes.\">Normalmente, veo la tele y hago mis deberes.</span> — even if you miss a word, recognising the chunk <span data-say=\"me gusta\">me gusta</span> (I like) or <span data-say=\"tengo que\">tengo que</span> (I have to) tells you instantly what kind of information is coming next.</p>\n            <p>The number of marks for a question tells you how many separate details are needed — a 2-mark question needs two distinct pieces of information.</p>", "check": {"question": "What is the best use of the 5-minute reading time before Section A?", "options": ["Read every question, underline key words and predict the type of answer needed", "Skip straight to writing full English sentences for every possible answer before listening", "Memorise the whole question paper word for word before listening", "Ignore the questions and just wait quietly for the recording to begin"], "answer": 0, "explain": "Reading and predicting first means you already know what to listen for once the audio starts."}}, {"title": "Recognising numbers, times, dates and days", "html": "<p>Numbers, times and dates carry a lot of marks in Section A because they are precise, checkable details. Learn to recognise them <strong>instantly</strong>, without translating word by word.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el lunes\">el lunes</span></td><td>Monday</td><td><span data-say=\"el miércoles\">el miércoles</span></td><td>Wednesday</td></tr>\n              <tr><td><span data-say=\"el sábado\">el sábado</span></td><td>Saturday</td><td><span data-say=\"el domingo\">el domingo</span></td><td>Sunday</td></tr>\n              <tr><td><span data-say=\"a la una\">a la una</span></td><td>at one o''clock</td><td><span data-say=\"el mediodía\">el mediodía</span></td><td>midday</td></tr>\n              <tr><td><span data-say=\"a las ocho y media\">a las ocho y media</span></td><td>at half past eight</td><td><span data-say=\"a las diez menos cuarto\">a las diez menos cuarto</span></td><td>at quarter to ten</td></tr>\n              <tr><td><span data-say=\"el primero de enero\">el primero de enero</span></td><td>the 1st of January</td><td><span data-say=\"el treinta de abril\">el treinta de abril</span></td><td>the 30th of April</td></tr>\n            </table>\n            <p>Tip: listen for the pattern <span data-say=\"a las...\">a las…</span> for clock times, and <span data-say=\"el... de...\">el … de …</span> for dates — you don''t need every word, just spot the pattern and grab the number.</p>", "check": {"question": "Which strategy helps most when listening for a date in the recording?", "options": ["Spot the pattern ‘el … de …’ and focus on grabbing the number", "Wait for the whole sentence to be translated silently in your head first", "Only write down a date if you hear the day of the week too", "Ignore dates completely, since they are rarely worth marks"], "answer": 0, "explain": "Spanish dates follow a fixed pattern (el + number + de + month), so recognising the pattern lets you grab the number fast."}}, {"title": "Negatives and distractors — don''t get caught out", "html": "<p>Exam recordings are deliberately designed to include <strong>distractors</strong> — words you recognise that are <em>not</em> the answer, often because a negative flips the meaning.</p>\n            <ul>\n              <li><span data-say=\"no\">no</span> — not / no</li>\n              <li><span data-say=\"nunca\">nunca</span> — never</li>\n              <li><span data-say=\"nada\">nada</span> — nothing</li>\n              <li><span data-say=\"tampoco\">tampoco</span> — neither / not … either</li>\n            </ul>\n            <p>Example: <span data-say=\"Antes me gustaba el fútbol, pero ya no me gusta nada.\">Antes me gustaba el fútbol, pero ya no me gusta nada.</span> — <em>I used to like football, but I don''t like it at all now.</em> The recording says ‘fútbol’, but the negative at the end means it is <strong>not</strong> a current hobby.</p>\n            <p>Watch for <span data-say=\"tampoco\">tampoco</span> too: <span data-say=\"A mí tampoco me gusta la geografía.\">A mí tampoco me gusta la geografía.</span> — <em>I don''t like geography either.</em></p>", "check": {"question": "Why are negative words like ‘nunca’ or ‘no’ so important to catch while listening?", "options": ["They can completely reverse the meaning of the sentence you are listening to", "They are always the very first word in a Spanish sentence", "They only ever appear in Higher-tier recordings, never in Foundation-tier papers", "They tell you the recording has finished and it is time to write"], "answer": 0, "explain": "A single negative word can flip a whole sentence''s meaning, which is exactly how the exam builds distractors."}}, {"title": "Section B: Dictation — what happens?", "html": "<p>Section B is <strong>dictation</strong> — you hear short sentences and write down <em>exactly</em> what is said, word for word, punctuation included. It is worth <strong>8 marks at Foundation / 10 marks at Higher</strong>.</p>\n            <p>A few of the words will come from <strong>outside</strong> the GCSE vocabulary list — don''t panic, just write your best attempt using normal Spanish spelling rules; a reasonable attempt can still gain credit, but a blank cannot.</p>\n            <p>Golden rules: use the pauses to write (not to guess ahead), then use the final play-through to check spelling and add any accents you can hear.</p>\n            <p>Try it: listen to this example — <span data-say=\"Mi hermano tiene el pelo rizado y es muy simpático.\" data-listen></span> — then check: <em>Mi hermano tiene el pelo rizado y es muy simpático.</em> (My brother has curly hair and is very nice.)</p>", "check": {"question": "How many marks is Section B (dictation) worth at Foundation tier?", "options": ["8 marks", "40 marks", "0 marks — it is not assessed at Foundation", "25 marks"], "answer": 0, "explain": "Section B (dictation) is 8 marks at Foundation and 10 marks at Higher; Section A carries the bulk of the marks (32/40)."}}, {"title": "Higher: matching sound to spelling in dictation", "html": "<p><span class=\"tier-h\">H</span> Spanish spelling follows the sound closely, but these patterns catch students out in dictation:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>soft c / z</td><td><span data-say=\"cero\">cero</span>, <span data-say=\"cinco\">cinco</span>, <span data-say=\"zapato\">zapato</span> — c before e/i, and z, make a soft \"th/s\" sound</td></tr>\n              <tr><td>throaty g / j</td><td><span data-say=\"jueves\">jueves</span>, <span data-say=\"gente\">gente</span> — j always, and g before e/i, make a throaty \"h\" sound</td></tr>\n              <tr><td>silent h</td><td><span data-say=\"hermano\">hermano</span>, <span data-say=\"hay\">hay</span> — h is never pronounced, so listen for the vowel that follows</td></tr>\n              <tr><td>ñ</td><td><span data-say=\"español\">español</span>, <span data-say=\"año\">año</span> — a completely different letter to plain n</td></tr>\n              <tr><td>rr</td><td><span data-say=\"perro\">perro</span> vs <span data-say=\"pero\">pero</span> — a rolled rr changes the whole word</td></tr>\n            </table>\n            <p><span class=\"tier-h\">H</span> Add accents where you can hear the stress fall somewhere unexpected, e.g. <span data-say=\"está\">está</span>, <span data-say=\"música\">música</span> — but getting the letters right matters more than a missing accent.</p>", "check": {"question": "Why does dictation test the difference between ‘perro’ and ‘pero’?", "options": ["A rolled rr versus a single r changes the whole word and its meaning", "‘perro’ and ‘pero’ are pronounced in exactly the same way, so it never really matters", "Only Foundation students need to know this distinction", "The letters r and rr are always interchangeable in Spanish spelling"], "answer": 0, "explain": "perro (dog) and pero (but) sound different because of the rolled rr — writing the wrong one changes the word completely."}}]}, "terms": {"enabled": true, "pairs": [{"term": "escuchar", "definition": "to listen"}, {"term": "la grabación", "definition": "the recording"}, {"term": "comprender", "definition": "to understand"}, {"term": "contestar", "definition": "to answer"}, {"term": "el dictado", "definition": "the dictation"}, {"term": "la respuesta", "definition": "the answer"}, {"term": "subrayar", "definition": "to underline (key words)"}, {"term": "el tiempo de lectura", "definition": "the reading time"}, {"term": "repetir", "definition": "to repeat"}, {"term": "deletrear", "definition": "to spell out"}, {"term": "la tilde", "definition": "the accent mark"}, {"term": "predecir", "definition": "to predict"}, {"term": "nunca / no / nada", "definition": "never / not / nothing — meaning-flipping negatives"}, {"term": "tampoco", "definition": "neither / not … either"}, {"term": "a las…", "definition": "at … o''clock (clock times)"}, {"term": "el … de …", "definition": "the … of … (dates)"}, {"term": "rizado (H)", "definition": "curly — a common dictation spelling test"}, {"term": "la ñ y la rr (H)", "definition": "the letters ñ and rr — never the same as n or r"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Tengo un hermano mayor y una hermana menor.\" data-listen></span><br>Listen. What does the speaker say about their siblings?", "options": ["An older brother and a younger sister", "A younger brother and an older sister", "Two older brothers and no sisters at all", "An older sister who lives with a younger brother in Madrid"], "answer": 0, "explain": "mayor = older, menor = younger. Trap B simply swaps the two around; trap D adds invented detail."}, {"question": "<span data-say=\"Normalmente hago mis deberes después de cenar.\" data-listen></span><br>Listen. When does the speaker usually do their homework?", "options": ["After dinner", "Before dinner", "Straight after school finishes, every single day", "Every morning before going to school, without fail"], "answer": 0, "explain": "‘después de cenar’ = after dinner. The other options invent a different time that was never said."}, {"question": "<span data-say=\"El sábado que viene voy a ir a un concierto.\" data-listen></span><br>Listen. What are the speaker''s plans?", "options": ["Going to a concert next Saturday", "Going to a concert last Saturday", "Staying home quietly next Saturday", "Going to a football match next Saturday evening with friends"], "answer": 0, "explain": "‘el sábado que viene’ = next Saturday (future); trap B swaps it to the past, trap D invents a different event."}, {"question": "<span data-say=\"Nunca voy al gimnasio porque no tengo tiempo.\" data-listen></span><br>Listen. What does the speaker say?", "options": ["They never go to the gym because they don''t have time", "They go to the gym every day because they have plenty of time", "They sometimes go to the gym at the weekend, if there''s time", "They used to go to the gym a lot but stopped last year after an injury"], "answer": 0, "explain": "‘nunca … no tengo tiempo’ = never … because I don''t have time. Trap B reverses both the frequency and the reason."}, {"question": "<span data-say=\"Mi hermana quería ser médica, pero al final decidió estudiar para ser profesora.\" data-listen></span><br>Listen. What does the speaker''s sister want to be NOW?", "options": ["A teacher", "A doctor", "Both a doctor and a teacher at the same time", "A doctor, but only after training as a teacher first"], "answer": 0, "explain": "‘médica’ is mentioned only to be rejected by ‘pero al final decidió’ — the final choice is profesora (teacher)."}, {"question": "<span data-say=\"Mi cumpleaños es el treinta de abril.\" data-listen></span><br>Listen. When is the speaker''s birthday?", "options": ["The 30th of April", "The 13th of April", "The 30th of August", "The 3rd of April, the same day as her brother''s"], "answer": 0, "explain": "treinta = 30 (not trece = 13), and abril = April (not agosto = August)."}, {"question": "In the 5 minutes'' reading time before Section A starts, what is the BEST use of your time?", "options": ["Read every question and predict what kind of answer each one needs", "Write out full English sentences for every possible answer in advance", "Memorise the entire question paper word for word before listening", "Skip ahead and read only the final question, since it carries the most marks"], "answer": 0, "explain": "Reading and predicting turns the reading time into real preparation for the listening that follows."}, {"question": "In Section B (dictation), what should you do during the final play-through of each sentence?", "options": ["Check your spelling and add any missing accents you can hear", "Ignore it completely and move straight to the next sentence", "Translate the whole sentence into English instead of writing down the Spanish you hear", "Count how many words the sentence contains and nothing else"], "answer": 0, "explain": "The extra play-through exists so you can proof-read what you''ve already written, not to redo it."}, {"question": "A recording mentions <span data-say=\"el fútbol\">el fútbol</span> but then adds <span data-say=\"ya no me gusta nada\" data-listen></span>. What does this test?", "options": ["Whether you notice the negative flips the meaning, so football is NOT the answer", "Whether you can spell ‘fútbol’ correctly, including the accent", "Whether you know the plural form of ‘el fútbol’", "Whether you can translate the whole sentence into perfect, fully accented Higher-tier Spanish"], "answer": 0, "explain": "This is exactly how a distractor works — the word is said, then rejected by the negative that follows."}, {"question": "<span data-say=\"Mi hermano tiene el pelo rizado y los ojos verdes.\" data-listen></span><br>Listen. What does the speaker describe?", "options": ["Their brother''s curly hair and green eyes", "Their brother''s straight hair and blue eyes", "Their sister''s curly hair and green eyes", "Their brother''s curly hair, green eyes and a small scar above one eyebrow"], "answer": 0, "explain": "rizado = curly, verdes = green, hermano = brother. Every distractor swaps one true detail for a false one."}]}, "fib": {"enabled": true, "questions": [{"text": "Mi hermano tiene el pelo [rizado]. <span data-say=\"Mi hermano tiene el pelo rizado.\" data-listen></span>"}, {"text": "Vivo en una casa [grande] en las afueras de la ciudad. <span data-say=\"Vivo en una casa grande en las afueras de la ciudad.\" data-listen></span>"}, {"text": "Compré unos [zapatos] nuevos para el gimnasio. <span data-say=\"Compré unos zapatos nuevos para el gimnasio.\" data-listen></span>"}, {"text": "Voy a la piscina todos los [jueves]. <span data-say=\"Voy a la piscina todos los jueves.\" data-listen></span>"}, {"text": "Tengo un [hermano] que se llama Pablo. <span data-say=\"Tengo un hermano que se llama Pablo.\" data-listen></span>"}, {"text": "Estudio [español] en el instituto. <span data-say=\"Estudio español en el instituto.\" data-listen></span>"}, {"text": "Usa el tiempo de lectura para [predecir] lo que se va a preguntar. (to predict)"}]}, "tf": {"enabled": true, "questions": [{"statement": "Paper 1 (Listening) is worth 25% of the whole GCSE.", "answer": true, "explain": "Correct — Listening is one of four papers, each worth 25%."}, {"statement": "Section B (dictation) is worth more marks than Section A (comprehension).", "answer": false, "explain": "The opposite is true — Section A carries 32/40 marks, Section B only 8/10."}, {"statement": "Listen: <span data-say=\"Voy a leer todas las preguntas antes de escuchar la grabación.\" data-listen></span> — this describes GOOD exam technique for Paper 1.", "answer": true, "explain": "Reading every question before the recording starts is exactly the technique this page teaches."}, {"statement": "A negative word like ‘nunca’ or ‘no’ can completely flip the meaning of a sentence you are listening to.", "answer": true, "explain": "This is exactly how exam recordings build distractors."}, {"statement": "Listen: <span data-say=\"Mi madre trabaja en un hospital y mi padre es profesor.\" data-listen></span> — the statement claims the speaker''s father is a teacher.", "answer": true, "explain": "‘mi padre es profesor’ = my father is a teacher; the mother works in a hospital."}, {"statement": "Listen: <span data-say=\"Nunca he estudiado francés.\" data-listen></span> — this means the speaker studies French every day.", "answer": false, "explain": "‘nunca he estudiado francés’ = I have never studied French — the exact opposite meaning."}, {"statement": "In dictation, you only need to write the general meaning of the sentence, not the exact words.", "answer": false, "explain": "Dictation requires an exact, correctly spelled transcription, not a paraphrase."}, {"statement": "Adding a missing accent, like on ‘está’, can matter for full marks in Higher-tier dictation.", "answer": true, "explain": "Accents are part of correct spelling, so at Higher tier they can affect the mark."}]}, "misc": {"enabled": true, "items": [{"myth": "In Section B, you can write a rough paraphrase of what you hear instead of the exact words.", "truth": "In Section B, you must write EXACTLY what you hear, correctly spelled — dictation tests exact transcription, not paraphrase.", "check": {"question": "What is required in Section B (dictation)?", "options": ["Writing exactly what you hear, spelled correctly", "Writing a rough summary in your own words", "Translating the sentence into English instead", "Writing only the first and last word of each sentence"], "answer": 0, "explain": "Dictation marks are for accurate transcription, not a summary or a translation."}}, {"myth": "If a dictation sentence includes a word outside your vocabulary list, you should leave that part blank.", "truth": "Even for unfamiliar words, write your best attempt using normal Spanish sound-spelling rules — a reasonable attempt can gain credit, but a blank cannot.", "check": {"question": "A dictation sentence includes a word outside your vocabulary list. What should you do?", "options": ["Attempt a spelling using normal Spanish sound-spelling patterns", "Leave that part of the sentence blank since it isn''t on the list", "Write the nearest English word in its place instead", "Stop writing completely and skip to the next sentence"], "answer": 0, "explain": "A sensible attempt using normal Spanish spelling rules can still earn credit; a blank definitely cannot."}}, {"myth": "Words like ‘no’ or ‘nunca’ are minor details you can usually skip when listening for the answer.", "truth": "A negative like ‘no’ or ‘nunca’ can completely reverse a sentence''s meaning, so it is often the MOST important word to catch.", "check": {"question": "Why should you never skip past a negative word while listening?", "options": ["It can completely reverse the meaning of the whole sentence", "Negatives are only ever used in Higher-tier recordings", "Negatives always come at the very start of a Spanish sentence", "Skipping negatives makes the recording easier to follow"], "answer": 0, "explain": "A missed negative is one of the most common reasons students pick the wrong answer in Section A."}}, {"myth": "The 5 minutes'' reading time at the start of Paper 1 is just for reading instructions, so it barely matters.", "truth": "The reading time is for reading every question and predicting what to listen for — using it well makes the actual listening much easier.", "check": {"question": "What is the reading time at the start of Paper 1 actually for?", "options": ["Reading every question and predicting what kind of answer is needed", "Reading only the front-cover instructions and general exam rules, nothing else", "Filling in your name and candidate number very slowly", "Nothing important — it can safely be skipped altogether"], "answer": 0, "explain": "Predicting the question types before the recording starts is the whole point of the reading time."}}, {"myth": "Once you have written an answer in Section A, there is no need to check it again.", "truth": "The 2 minutes at the end of the exam are for checking your answers make sense (an age of 200, for example, is clearly wrong) — always use them.", "check": {"question": "What are the final 2 minutes of Paper 1 for?", "options": ["Checking your answers make sense and correcting obvious mistakes", "Starting Section B (dictation) again from the very beginning of the recording", "Copying your answers onto a separate answer sheet", "Nothing — the exam is effectively already finished by then"], "answer": 0, "explain": "The final 2 minutes exist specifically so you can catch and fix obvious errors before time is called."}}]}, "tips": {"enabled": true, "items": [{"title": "Section A — predict before you listen", "html": "Use the 5-minute reading window to read every question and predict what is coming, e.g. <span data-say=\"¿Qué le gusta hacer los fines de semana?\" data-listen></span> signals an OPINION or ACTIVITY answer is needed. Predicting the answer type before the audio starts means you already know what to listen out for.", "check": {"question": "Why predict the type of answer needed BEFORE the recording starts?", "options": ["So you already know what kind of information to listen out for", "So you can write the full answer before hearing anything in the recording at all", "Because predicting is required by the exam board''s rules", "So you can skip listening to that question altogether"], "answer": 0, "explain": "Predicting focuses your listening on exactly the detail the question is asking for."}}, {"title": "Section B — dictation strategy", "html": "Write down what you hear using normal sound-spelling rules — soft c/z, throaty g/j, silent h, ñ and rr all matter, e.g. <span data-say=\"Voy a la piscina los jueves.\" data-listen></span>. Use the final play-through only to check spelling and accents, not to rewrite from scratch.", "check": {"question": "What should the FINAL play-through of a dictation sentence be used for?", "options": ["Checking spelling and adding any accents you can hear", "Writing the sentence down completely for the very first time", "Translating the sentence into English", "Deciding whether to answer that sentence at all"], "answer": 0, "explain": "By the final play-through you should already have a full attempt written — it is a check, not a first draft."}}, {"title": "Using the reading time and the checking time", "html": "Two windows of time are easy to waste: the 5 minutes before the recording (read every question, underline key words) and the 2 minutes after (check answers make sense — <span data-say=\"Después de escuchar, tienes dos minutos para comprobar tus respuestas.\" data-listen></span>). An age of 200, or a day that doesn''t exist, is an obvious sign an answer needs another look.", "check": {"question": "Which pair of exam-time habits gets the most out of Paper 1?", "options": ["Predicting from every question first, then checking answers make sense at the end", "Listening carefully but ignoring the reading time and the final checking time completely", "Writing answers only during the checking time at the very end", "Reading the questions after the recording has already finished"], "answer": 0, "explain": "Both windows are graded time you are given for a reason — predicting first and checking last."}}]}, "exam": {"enabled": true, "questions": [{"question": "You will hear four short sentences. Tap 🔊 on each one and write EXACTLY what you hear, spelling every word correctly.<br>\n            (a) <span data-say=\"Mi hermano tiene el pelo rizado.\" data-listen></span><br>\n            (b) <span data-say=\"Vamos a la piscina los jueves.\" data-listen></span><br>\n            (c) <span data-say=\"Nunca como carne los fines de semana.\" data-listen></span><br>\n            (d) <span data-say=\"Voy a estudiar español el año que viene.\" data-listen></span>", "marks": 8, "hint": "Listen once for the general sentence, then again to check spelling — watch for jueves (throaty j), nunca (a negative), and the ñ in español.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 8 marks (AO3 Listening: dictation, Foundation)</h5><ul>\n                <li><strong>(a)</strong> Mi hermano tiene <em>(1)</em> el pelo rizado <em>(1)</em>.</li>\n                <li><strong>(b)</strong> Vamos a la piscina <em>(1)</em> los jueves <em>(1)</em>.</li>\n                <li><strong>(c)</strong> Nunca como carne <em>(1)</em> los fines de semana <em>(1)</em>.</li>\n                <li><strong>(d)</strong> Voy a estudiar español <em>(1)</em> el año que viene <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>One mark per correctly spelled chunk shown above; minor accent slips may still cost the mark at this tier if the letters are also wrong.</li>\n            </ul></div>"}, {"question": "<span class=\"tier-h\">H</span> You will hear four short sentences. Tap 🔊 on each one and write EXACTLY what you hear, spelling every word correctly, with accents where you can.<br>\n            (a) <span data-say=\"Mi madre es médica y trabaja en el hospital.\" data-listen></span><br>\n            (b) <span data-say=\"El sábado que viene voy a comprar unos zapatos nuevos.\" data-listen></span><br>\n            (c) <span data-say=\"Mi hermano mayor estudia inglés en la universidad.\" data-listen></span><br>\n            (d) <span data-say=\"Después del examen, estaba muy cansado pero contento.\" data-listen></span>", "marks": 10, "hint": "Watch for the accents on médica, sábado and inglés, the soft z sound in zapatos, and the rolled rr is NOT present in pero (but) — don''t confuse it with perro (dog).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 10 marks (AO3 Listening: dictation, Higher)</h5><ul>\n                <li><strong>(a)</strong> Mi madre es médica <em>(1)</em> y trabaja <em>(1)</em> en el hospital <em>(1)</em>.</li>\n                <li><strong>(b)</strong> El sábado que viene <em>(1)</em> voy a comprar <em>(1)</em> unos zapatos nuevos <em>(1)</em>.</li>\n                <li><strong>(c)</strong> Mi hermano mayor <em>(1)</em> estudia inglés en la universidad <em>(1)</em>.</li>\n                <li><strong>(d)</strong> Después del examen <em>(1)</em> estaba muy cansado pero contento <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>One mark per correctly spelled chunk; at Higher, an accent that changes a word''s identity (e.g. médica) is expected for the mark.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', '{"learn": {"enabled": true, "items": [{"title": "What does AQA Paper 3 actually test?", "html": "<p>Paper 3 is a <strong>written Reading exam</strong>: <span data-say=\"cuarenta y cinco minutos\">45 minutes</span> at Foundation, <span data-say=\"una hora\">1 hour</span> at Higher. It is worth <strong>50 marks</strong> — <strong>25%</strong> of your final GCSE grade.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>Section A</td><td>Reading comprehension — questions <strong>in English</strong>, answered <strong>in English or non-verbally</strong> (a tick, box or letter). 40 marks. Includes inferring the meaning of an unknown word from context.</td></tr>\n              <tr><td>Section B</td><td><strong>Translation</strong> of a Spanish text <strong>into English</strong>. Minimum <span data-say=\"treinta y cinco palabras\">35 words</span> (Foundation) / <span data-say=\"cincuenta palabras\">50 words</span> (Higher). 10 marks.</td></tr>\n            </table>\n            <p>Instruction you will see on the paper: <span data-say=\"Traduce este texto al inglés.\">Traduce este texto al inglés.</span> — <em>Translate this text into English.</em></p>", "check": {"question": "How many marks is Paper 3 worth in total?", "options": ["50 marks", "40 marks", "60 marks", "25 marks"], "answer": 0, "explain": "Paper 3 is worth 50 marks in total — 40 for Section A and 10 for Section B — and is 25% of the GCSE."}}, {"title": "Section A: how to read strategically", "html": "<p>Don''t read word by word from the top. Use a two-step strategy:</p>\n            <ol>\n              <li><strong>Skim</strong> the whole text quickly first, for the general gist — what is it about?</li>\n              <li>Then <strong>scan</strong> for the specific detail each question asks for.</li>\n            </ol>\n            <p>Spotting these connectors while skimming helps you follow the logic of a text:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"sin embargo\">sin embargo</span></td><td>however</td><td><span data-say=\"además\">además</span></td><td>furthermore / also</td></tr>\n              <tr><td><span data-say=\"por eso\">por eso</span></td><td>that''s why / so</td><td><span data-say=\"aunque\">aunque</span></td><td>although</td></tr>\n            </table>", "check": {"question": "What should you do FIRST when reading a text in Section A?", "options": ["Skim the whole text quickly for the general gist", "Look up every unknown word in a dictionary immediately", "Translate the entire text into English word by word", "Answer question 1 without reading the rest of the text"], "answer": 0, "explain": "Skim first for the gist, then scan for the specific detail each question needs — don''t translate the whole thing or dictionary-hunt every word."}}, {"title": "Inferring the meaning of unknown words", "html": "<p>Section A also tests whether you can work out a <strong>plausible meaning</strong> for a word you don''t already know, using context and word families — you are not expected to know every word.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"descubrir\">descubrir</span></td><td>des- + cubrir (to cover) → to discover / uncover</td></tr>\n              <tr><td><span data-say=\"inolvidable\">inolvidable</span></td><td>in- + olvidar (to forget) + -able → unforgettable</td></tr>\n              <tr><td><span data-say=\"desconocido\">desconocido</span></td><td>des- + conocido (known) → unknown</td></tr>\n              <tr><td><span data-say=\"rápidamente\">rápidamente</span></td><td>rápido (fast) + -mente → quickly</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Los científicos descubrieron una nueva especie de pájaro.\">Los científicos descubrieron una nueva especie de pájaro.</span> — <em>The scientists discovered a new species of bird.</em></p>", "check": {"question": "In ''descubrieron'' (des- + cubrir), what does the prefix ''des-'' generally signal?", "options": ["a reversal or undoing of the root word''s action", "that the word must be a false friend you cannot trust at all", "that the verb is definitely in the future tense", "that the word describes a physical size"], "answer": 0, "explain": "des- typically reverses or undoes the root: cubrir (to cover) → descubrir (to uncover/discover)."}}, {"title": "False friends — the #1 trap", "html": "<p>A <strong>false friend</strong> looks like an English word but means something different. Learn these before Paper 3:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"sensible\">sensible</span></td><td>sensitive (NOT sensible)</td></tr>\n              <tr><td><span data-say=\"constipado\">constipado</span></td><td>having a cold (NOT constipated)</td></tr>\n              <tr><td><span data-say=\"éxito\">éxito</span></td><td>success (NOT exit)</td></tr>\n              <tr><td><span data-say=\"ropa\">ropa</span></td><td>clothes (NOT rope)</td></tr>\n              <tr><td><span data-say=\"largo\">largo</span></td><td>long (NOT large)</td></tr>\n              <tr><td><span data-say=\"embarazada\">embarazada</span></td><td>pregnant (NOT embarrassed)</td></tr>\n            </table>\n            <p>Examples: <span data-say=\"Mi madre está embarazada.\">Mi madre está embarazada.</span> (My mother is pregnant.) · <span data-say=\"Estoy constipado.\">Estoy constipado.</span> (I have a cold.)</p>", "check": {"question": "Which of these correctly matches the Spanish word to its true English meaning?", "options": ["constipado = having a cold", "sensible = sensible / practical", "éxito = an exit", "ropa = a rope"], "answer": 0, "explain": "constipado = having a cold. The other three are the WRONG literal guesses — exactly the false-friend trap examiners test."}}, {"title": "Section B: how the translation is marked", "html": "<p>Section B gives you a short Spanish text to translate <strong>into English</strong>. It is marked in <strong>chunks of meaning</strong>, not word by word — the examiner ticks each idea you translate correctly.</p>\n            <ul>\n              <li>Translate the <strong>sense</strong> of each phrase naturally — don''t translate word for word.</li>\n              <li>Keep the <strong>tense</strong> of the Spanish verb: <span data-say=\"fui\">fui</span> = I went (one completed action); <span data-say=\"iba\">iba</span> = I used to go / I was going (an ongoing or repeated action).</li>\n              <li>Idioms need a natural English equivalent: <span data-say=\"Se me olvidó el cumpleaños de mi amigo.\">Se me olvidó el cumpleaños de mi amigo.</span> = I forgot my friend''s birthday — NOT \"it forgot itself to me\".</li>\n              <li>Never leave a gap. If a word is unknown, use context or a cognate to make a sensible attempt.</li>\n            </ul>", "check": {"question": "Section B is worth how many marks, and what is it testing?", "options": ["10 marks — translating a Spanish passage into English", "40 marks — answering comprehension questions in English", "50 marks — the whole of Paper 3 combined", "25 marks — a mix of reading and writing tasks"], "answer": 0, "explain": "Section B is the translation task, worth 10 of the paper''s 50 marks."}}, {"title": "Higher: tense accuracy and natural English", "html": "<p><span class=\"tier-h\">H</span> Higher-tier translation passages add more complex tenses. You must still keep the tense in your English:</p>\n            <ul>\n              <li><span data-say=\"Había terminado los deberes antes de cenar.\">Había terminado los deberes antes de cenar.</span> <span class=\"tier-h\">H</span> — I had finished my homework before dinner (pluperfect: an action before another past action).</li>\n              <li><span data-say=\"Si tuviera más tiempo, viajaría más.\">Si tuviera más tiempo, viajaría más.</span> <span class=\"tier-h\">H</span> — If I had more time, I would travel more (conditional).</li>\n              <li><span data-say=\"Aunque llovía, decidimos salir.\">Aunque llovía, decidimos salir.</span> <span class=\"tier-h\">H</span> — Although it was raining, we decided to go out.</li>\n            </ul>\n            <p>Once you have a draft translation, always re-read it and ask: <em>does this sound like natural English, or does it sound translated?</em></p>", "check": {"question": "Which translation correctly reflects the tense of ''Había terminado los deberes antes de cenar''?", "options": ["I had finished my homework before having dinner", "I finish my homework before having dinner", "I will finish my homework before having dinner", "I am currently in the middle of finishing my homework before dinner"], "answer": 0, "explain": "''había terminado'' is the pluperfect — an action completed before another past action — so it must be ''I had finished''."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Paper 3", "definition": "Reading exam: 45 min (Foundation) / 1 hour (Higher), 50 marks total, 25% of the GCSE"}, {"term": "Section A", "definition": "Reading comprehension — questions in English, answered in English or non-verbally (40 marks)"}, {"term": "Section B", "definition": "Translation from Spanish into English (10 marks)"}, {"term": "número mínimo de palabras", "definition": "minimum word count: 35 words (Foundation) / 50 words (Higher)"}, {"term": "cognado", "definition": "cognate — a word that looks/sounds similar in Spanish and English, e.g. ''información''"}, {"term": "falso amigo", "definition": "false friend — looks similar to an English word but means something different"}, {"term": "constipado", "definition": "having a cold (NOT constipated)"}, {"term": "sensible", "definition": "sensitive (NOT sensible / practical)"}, {"term": "éxito", "definition": "success (NOT exit)"}, {"term": "ropa", "definition": "clothes (NOT rope)"}, {"term": "largo", "definition": "long (NOT large)"}, {"term": "embarazada", "definition": "pregnant (NOT embarrassed)"}, {"term": "fui (pretérito)", "definition": "I went — one completed action in the past"}, {"term": "iba (imperfecto)", "definition": "I used to go / I was going — an ongoing or repeated past action"}, {"term": "traducir el sentido", "definition": "translate the sense/meaning of a phrase, not word for word"}, {"term": "había hecho (H)", "definition": "I had done — pluperfect tense, for an action before another past action"}, {"term": "inferir por contexto", "definition": "to infer an unknown word''s meaning from context or its word family"}, {"term": "skim y scan", "definition": "skim for the general gist first, then scan for specific details"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Fui al cine ayer.\" data-listen></span><br>Listen. What is the correct translation?", "options": ["I go to the cinema every day", "I went to the cinema yesterday", "I am going to the cinema now", "I have been to the cinema many times before"], "answer": 1, "explain": "''fui'' = I went (pretérito, one completed past action). The traps swap to a habit, a present plan, or the present perfect."}, {"question": "<span data-say=\"Iba al gimnasio todos los días.\" data-listen></span><br>Listen. What is the correct translation?", "options": ["I went to the gym just once, yesterday afternoon", "I have never really gone to the gym before", "I used to go to the gym every day", "I am going to the gym today, just this once"], "answer": 2, "explain": "''iba'' = I used to go (imperfecto, a repeated/ongoing past habit). Trap A wrongly uses the preterite (one single event)."}, {"question": "In the sentence <span data-say=\"Mi madre está embarazada.\">\"Mi madre está embarazada,\"</span> what does <em>embarazada</em> mean?", "options": ["pregnant", "embarrassed", "in a hurry", "on holiday"], "answer": 0, "explain": "embarazada = pregnant. It is a classic false friend — it does NOT mean embarrassed."}, {"question": "What does <em>sensible</em> mean when used in Spanish, as in <span data-say=\"Es una persona muy sensible.\">\"Es una persona muy sensible\"</span>?", "options": ["sensible / practical", "intelligent", "friendly", "sensitive"], "answer": 3, "explain": "sensible = sensitive. The English-looking meaning (''sensible/practical'') is the false-friend trap."}, {"question": "Read: \"Los científicos descubrieron una nueva especie de pájaro en la selva.\" Using the word family \"des-\" + \"cubrir\" (to cover), what does <em>descubrieron</em> most likely mean?", "options": ["covered up", "destroyed", "described", "discovered"], "answer": 3, "explain": "des- + cubrir → discovered/uncovered. ''covered up'' is the literal-but-wrong trap; ''destroyed'' and ''described'' sound similar but are wrong."}, {"question": "In Section A of Paper 3, how should you answer the comprehension questions (unless told otherwise)?", "options": ["Always in full Spanish sentences copied from the text", "In Spanish, using your own words only", "In English, or non-verbally (e.g. a tick or box)", "With a single Spanish word for every answer"], "answer": 2, "explain": "Section A questions are in English and answered in English or non-verbally. Copying Spanish sentences does not answer the question."}, {"question": "Which approach is correct for the Section B translation task?", "options": ["Translate every single word literally, one by one, in the exact Spanish word order", "Translate the sense of each phrase naturally, keeping the correct tense", "Skip any sentence containing a word you don''t recognise", "Copy the Spanish words directly into your English answer unchanged"], "answer": 1, "explain": "Translate the sense of each phrase and keep the tense. Word-for-word literal translation is the #1 error examiners penalise."}, {"question": "Translate: <span data-say=\"Está constipado.\">\"Está constipado.\"</span>", "options": ["He is constipated", "He is very tired", "He is in a rush", "He has a cold"], "answer": 3, "explain": "constipado = having a cold. ''He is constipated'' is the obvious but wrong false-friend translation."}, {"question": "What is the minimum word count for the Section B translation at Higher tier?", "options": ["50 words", "35 words", "25 words", "100 words"], "answer": 0, "explain": "Higher tier requires a minimum of 50 words; Foundation requires 35 words — a common mix-up."}, {"question": "How many marks is the Section B translation task worth?", "options": ["40 marks", "25 marks", "10 marks", "50 marks"], "answer": 2, "explain": "Section B (translation) is worth 10 marks; 40 is Section A, 50 is the whole paper, 25 is the % weighting — not a mark total."}]}, "fib": {"enabled": true, "questions": [{"text": "<span data-say=\"Fui al cine.\">Fui al cine.</span> = I [went] to the cinema. (pretérito — a completed action)"}, {"text": "<span data-say=\"Iba a la playa cada verano.\">Iba a la playa cada verano.</span> = I [used] to go to the beach every summer. (imperfecto — a repeated action)"}, {"text": "<span data-say=\"Está constipado.\">Está constipado.</span> = He [has] a cold. (NOT constipated — false friend!)"}, {"text": "Mi hermana está [embarazada]. <span data-say=\"Mi hermana está embarazada.\" data-listen>Mi hermana está embarazada.</span>"}, {"text": "<span data-say=\"La ropa es cara.\">La ropa es cara.</span> In English, ''ropa'' means [clothes], not ''rope''."}, {"text": "<span data-say=\"Se me olvidó el cumpleaños de mi amigo.\">Se me olvidó el cumpleaños de mi amigo.</span> = I [forgot] my friend''s birthday. (idiom — translate the natural meaning, not word for word)"}, {"text": "<span data-say=\"El texto es largo.\">El texto es largo.</span> In English, ''largo'' means [long], not ''large''."}]}, "tf": {"enabled": true, "questions": [{"statement": "Paper 3 is a listening exam.", "answer": false, "explain": "Paper 3 is a WRITTEN Reading exam (45 min Foundation / 1 hour Higher)."}, {"statement": "In Section A, you must answer the comprehension questions in English or non-verbally.", "answer": true, "explain": "Section A questions are in English and answered in English or non-verbally (40 marks)."}, {"statement": "Section B is a translation from Spanish into English worth 10 marks.", "answer": true, "explain": "Section B = translation into English, 10 marks; minimum 35 (F) / 50 (H) words."}, {"statement": "The minimum word count for the Higher tier translation is 35 words.", "answer": false, "explain": "35 words is the Foundation minimum — Higher tier needs a minimum of 50 words."}, {"statement": "<span data-say=\"sensible\">''Sensible''</span> in Spanish means the same as ''sensible'' in English.", "answer": false, "explain": "False friend — Spanish ''sensible'' means sensitive, not practical/sensible."}, {"statement": "When translating <span data-say=\"Fui al cine.\">\"Fui al cine\"</span> into English, you should keep the tense of the original Spanish verb.", "answer": true, "explain": "''fui'' (went) and ''iba'' (used to go) must not be switched to the present tense in your translation."}, {"statement": "If you don''t know a word in the translation, it''s best to leave that part blank.", "answer": false, "explain": "Never leave a gap — use context, word families or cognates to make a sensible attempt."}, {"statement": "Paper 3 makes up 25% of the GCSE Spanish grade.", "answer": true, "explain": "Each of the four skills papers (Listening, Speaking, Reading, Writing) is worth 25%."}]}, "misc": {"enabled": true, "items": [{"myth": "Fui al cine. → translated as ''I go to the cinema.''", "truth": "Fui al cine. → I went to the cinema. (pretérito = a completed action, not the present)", "check": {"question": "What tense is ''fui'' in ''Fui al cine'', and what does that mean for the translation?", "options": ["Preterite — a single completed action, so it must be ''I went''", "Present — an ongoing habit, so it should be ''I go''", "Future — a plan, so it should be ''I will go''", "Imperfect — a repeated or ongoing action, so it should be ''I used to go''"], "answer": 0, "explain": "''fui'' is the preterite of ir — a single completed action in the past, so it must translate as ''I went''."}}, {"myth": "<span data-say=\"Está constipado.\">Está constipado.</span> → ''He is constipated.''", "truth": "Está constipado. → He has a cold. (false friend)", "check": {"question": "Why is ''He is constipated'' the wrong translation of ''Está constipado''?", "options": ["''constipado'' is a false friend that actually means ''having a cold''", "''constipado'' is a rare medical term that never appears on a GCSE reading paper at all", "''está'' means ''he was'' in the imperfect tense, not ''he is'' right now", "the sentence is actually posed as a question, not a statement"], "answer": 0, "explain": "constipado = having a cold — a classic Spanish/English false friend."}}, {"myth": "Se me olvidó el libro. → translated word-for-word as ''It forgot itself to me the book.''", "truth": "Se me olvidó el libro. → I forgot the book. (translate the natural English meaning, not each word)", "check": {"question": "What is the natural English translation of ''Se me olvidó el libro''?", "options": ["I forgot the book", "It forgot itself to me the book", "The book has forgotten me completely", "I remembered the book just in time"], "answer": 0, "explain": "Idioms like ''se me olvidó'' need a natural English equivalent — ''I forgot'' — not a literal word-for-word rendering."}}, {"myth": "Leaving a gap in the translation because a word is unknown.", "truth": "Use context, word family or a cognate to make a sensible, plausible attempt — never leave a gap.", "check": {"question": "What should you do with a word you don''t recognise during the translation task?", "options": ["Use context and word-family clues to attempt a sensible translation", "Leave a blank gap so you don''t risk losing extra marks for a wrong guess", "Copy the Spanish word into your English answer unchanged", "Skip the whole sentence that word appears in"], "answer": 0, "explain": "You can often infer a plausible meaning from context, cognates or the word''s root — never leave a gap."}}, {"myth": "<span data-say=\"Es una persona muy sensible.\">Es una persona muy sensible.</span> → ''He is a very sensible person.''", "truth": "Es una persona muy sensible. → He is a very sensitive person. (false friend)", "check": {"question": "Why is ''a very sensible person'' the wrong translation of ''una persona muy sensible''?", "options": ["Spanish ''sensible'' means sensitive, not practical/sensible", "''persona'' does not mean ''person'' at all anywhere in this whole sentence", "''muy'' changes the whole sentence into a question instead of a statement", "the sentence is written in the future tense, not the present"], "answer": 0, "explain": "sensible = sensitive in Spanish — the English-looking meaning is the false-friend trap."}}]}, "tips": {"enabled": true, "items": [{"title": "Section A — skim, then scan", "html": "Skim the whole text first for the general gist, then go back and scan for the specific detail each question needs. Don''t translate the whole text in your head before answering — that wastes time you need for later questions.", "check": {"question": "Why skim a text before answering any questions?", "options": ["To get the general gist quickly before hunting for detail", "Because the exam board requires a full written translation before you answer", "Because scanning for detail is not allowed anywhere in Section A", "To find and note down every single unknown word first"], "answer": 0, "explain": "Skimming gives you the gist fast; you then scan for the specific detail each question is really asking about."}}, {"title": "Section B — translate the sense, not the words", "html": "Translate each phrase as a whole idea, keep the Spanish verb''s tense in your English, and make idioms sound natural (e.g. ''se me olvidó'' = ''I forgot'', not a literal word-for-word version). Never leave a translation gap — a sensible attempt can still earn marks.", "check": {"question": "''Estoy resfriado y me duele la garganta'' should be translated as…", "options": ["I have a cold and my throat hurts", "I have a cold and my throat hurt yesterday", "I am tired and my whole back hurts", "I am fit and my legs hurt after running"], "answer": 0, "explain": "estar resfriado = to have a cold; la garganta = throat. Keep it in the present tense, as in the Spanish."}}, {"title": "Higher tier — tense accuracy earns marks", "html": "At Higher tier, passages mix tenses: pretérito, imperfecto, pluperfect (''había + past participle'') and conditional (''-ría''). Translate each one accurately — swapping ''había terminado'' (had finished) for ''finished'' loses the mark even if the rest of the sentence is right.", "check": {"question": "Which English translation correctly matches ''Si tuviera más tiempo, viajaría más''?", "options": ["If I had more time, I would travel more", "If I have more time, I will travel more often", "I had more time, so I travelled more", "I would have had more time to travel more"], "answer": 0, "explain": "''tuviera'' (imperfect subjunctive) + ''viajaría'' (conditional) = the classic ''if I had… I would…'' structure."}}]}, "exam": {"enabled": true, "questions": [{"question": "Translate this Spanish text into English.<br><br><em>\"Vivo en una ciudad pequeña con mi familia. Todos los días, voy al instituto en autobús. Ayer, jugué al fútbol con mis amigos y después fuimos al cine. Normalmente, hago mis deberes por la tarde, pero anoche estaba muy cansado.\"</em>", "marks": 10, "hint": "Translate phrase by phrase, not word for word. Watch the tenses: ''voy'' is present, ''jugué''/''fuimos'' are pretérito (completed actions) — and ''instituto'' means secondary school, not ''institute''.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 10 marks (AO4 Reading: translation)</h5><ul>\n                <li><strong>Chunk 1</strong> \"Vivo en una ciudad pequeña con mi familia.\" → I live in a small city/town with my family. <em>(2)</em></li>\n                <li><strong>Chunk 2</strong> \"Todos los días, voy al instituto en autobús.\" → Every day, I go to school by bus. <em>(2)</em></li>\n                <li><strong>Chunk 3</strong> \"Ayer, jugué al fútbol con mis amigos\" → Yesterday, I played football with my friends. <em>(2)</em></li>\n                <li><strong>Chunk 4</strong> \"y después fuimos al cine.\" → and afterwards we went to the cinema. <em>(2)</em></li>\n                <li><strong>Chunk 5</strong> \"Normalmente, hago mis deberes por la tarde, pero anoche estaba muy cansado.\" → Normally, I do my homework in the afternoon, but last night I was very tired. <em>(2)</em></li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>One tick per chunk translated with the correct sense and tense; do not penalise minor spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate this Spanish text into English.<br><br><em>\"El mes pasado, estuve enfermo y tuve que quedarme en casa. Me dolía la cabeza y estaba muy cansado. Sin embargo, no era nada grave. Mientras estaba en cama, leí un libro muy interesante sobre la historia de España. Espero sentirme mejor pronto.\"</em>", "marks": 10, "hint": "''estuve enfermo'' and ''tuve que'' are pretérito. ''Me dolía la cabeza'' works like gustar — keep it natural: ''my head hurt/ached''. ''Sin embargo'' = however.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 10 marks (AO4 Reading: translation)</h5><ul>\n                <li><strong>Chunk 1</strong> \"El mes pasado, estuve enfermo y tuve que quedarme en casa.\" → Last month, I was ill and I had to stay at home. <em>(2)</em></li>\n                <li><strong>Chunk 2</strong> \"Me dolía la cabeza y estaba muy cansado.\" → My head hurt/ached and I was very tired. <em>(2)</em></li>\n                <li><strong>Chunk 3</strong> \"Sin embargo, no era nada grave.\" → However, it wasn''t anything serious. <em>(2)</em></li>\n                <li><strong>Chunk 4</strong> \"Mientras estaba en cama, leí un libro muy interesante sobre la historia de España.\" → While I was in bed, I read a very interesting book about the history of Spain. <em>(2)</em></li>\n                <li><strong>Chunk 5</strong> \"Espero sentirme mejor pronto.\" → I hope to feel better soon. <em>(2)</em></li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept natural equivalents (e.g. ''my head ached''); penalise only if the sense or tense is wrong.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'x-3-speaking-read-aloud-and-photo-card', 'X.3 Speaking: Read-Aloud and Photo Card', '{"learn": {"enabled": true, "items": [{"title": "What is Paper 2 Speaking and how is it marked?", "html": "<p>Paper 2 is the <strong>Speaking Non-Exam Assessment (NEA)</strong> — worth <strong>50 marks, 25% of the whole GCSE</strong>. You get <span data-say=\"quince minutos\">quince minutos</span> (15 minutes) of supervised preparation time before you go in. There are three parts:</p>\n            <ul>\n              <li><strong><span data-say=\"el juego de rol\">el juego de rol</span></strong> (role-play) — 10 marks, about 1–1.5 minutes.</li>\n              <li>reading aloud + a short conversation — 15 marks: <span data-say=\"leer en voz alta\">leer en voz alta</span> (read a short text aloud), then an unprepared conversation.</li>\n              <li><strong><span data-say=\"la tarjeta con fotos\">la tarjeta con fotos</span></strong> (photo card) — 25 marks: describe the photo, then an unprepared conversation.</li>\n            </ul>", "check": {"question": "How many marks is the Photo Card part worth?", "options": ["25 marks — the biggest part of Paper 2", "15 marks, the same as the reading-aloud task", "10 marks, the same as the role-play", "50 marks — the whole of Paper 2"], "answer": 0, "explain": "The photo card is 25 of the 50 marks — half the paper. The role-play is 10 and reading aloud + conversation is 15."}}, {"title": "How do I read the text aloud accurately?", "html": "<p>Reading aloud is marked on <strong>pronunciation and intonation</strong>. Six sound rules cover most of what examiners listen for — tap 🔊 to hear each example.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"cabeza\">cabeza</span></td><td>soft c/z before e/i = a ‘th’ sound (Castilian), not a hard ‘k’ or an English ‘z’ buzz</td></tr>\n              <tr><td><span data-say=\"gente\">gente</span> / <span data-say=\"jugar\">jugar</span></td><td>throaty ‘g’ (before e/i) and ‘j’ — like clearing your throat, not an English ‘j’</td></tr>\n              <tr><td><span data-say=\"hacer\">hacer</span> / <span data-say=\"hola\">hola</span></td><td>the letter ‘h’ is always silent</td></tr>\n              <tr><td><span data-say=\"mañana\">mañana</span></td><td>‘ñ’ = ‘ny’, as in the English word ‘canyon’</td></tr>\n              <tr><td><span data-say=\"perro\">perro</span></td><td>double ‘rr’ is strongly rolled — different from a single ‘r’</td></tr>\n              <tr><td><span data-say=\"ejercicio\">ejercicio</span></td><td>each vowel keeps one pure, short sound — don’t blend them like English diphthongs</td></tr>\n            </table>\n            <p>Read steadily, not fast: <span data-say=\"Los fines de semana, hago ejercicio con mi hermano.\">Los fines de semana, hago ejercicio con mi hermano.</span></p>", "check": {"question": "In Castilian pronunciation, how should the ‘z’ in ‘cabeza’ sound?", "options": ["exactly like an English ‘z’ buzzing sound", "like the English ‘th’ in ‘think’", "silent — you don’t pronounce it at all", "like a rolled Spanish ‘rr’"], "answer": 1, "explain": "Castilian c/z before e/i is a soft ‘th’ sound. It is not a buzzing English z, not silent, and not the rr sound."}}, {"title": "How do I describe the photo card?", "html": "<p>For the Photo Card, start by <strong>describing what you see</strong> before giving opinions. Use these structures — tap 🔊 to hear them.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"en la foto hay\">en la foto hay…</span></td><td>in the photo there is / are…</td></tr>\n              <tr><td><span data-say=\"veo\">veo…</span></td><td>I see…</td></tr>\n              <tr><td><span data-say=\"hay una persona que\">hay una persona que…</span></td><td>there is a person who…</td></tr>\n            </table>\n            <p>Example: <span data-say=\"En la foto hay una familia. Veo a un chico que lleva una camiseta azul.\">En la foto hay una familia. Veo a un chico que lleva una camiseta azul.</span> — <em>In the photo there is a family. I see a boy wearing a blue T-shirt.</em></p>", "check": {"question": "Which phrase correctly starts a photo-card description?", "options": ["En la foto tiene dos personas", "En la foto son dos personas", "En la foto hay dos personas", "En la foto está dos personas"], "answer": 2, "explain": "‘hay’ (there is/are) is the correct impersonal verb for describing a photo. tiene/son/está are all wrong here."}}, {"title": "How do I describe the action with the present continuous?", "html": "<p>To describe the ACTION happening in the photo, use <strong>estar + gerund</strong> (present continuous):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"está comiendo\">está comiendo</span></td><td>he/she is eating</td><td><span data-say=\"está jugando\">está jugando</span></td><td>he/she is playing</td></tr>\n              <tr><td><span data-say=\"está leyendo\">está leyendo</span></td><td>he/she is reading</td><td><span data-say=\"están sonriendo\">están sonriendo</span></td><td>they are smiling</td></tr>\n            </table>\n            <p><span class=\"tier-h\">H</span> Watch the irregular gerunds: <span data-say=\"leyendo\">leer → leyendo</span>, <span data-say=\"durmiendo\">dormir → durmiendo</span>, <span data-say=\"pidiendo\">pedir → pidiendo</span>.</p>\n            <p>Example: <span data-say=\"En la foto, el niño está jugando en el jardín mientras su madre está leyendo.\">En la foto, el niño está jugando en el jardín mientras su madre está leyendo.</span></p>", "check": {"question": "Which is the correct present continuous for ‘eating’?", "options": ["está come", "está comer", "estás comiendo", "está comiendo"], "answer": 3, "explain": "Present continuous = está + gerund → está comiendo. ‘está come’ and ‘está comer’ don’t use the gerund; ‘estás’ is the wrong subject (tú, not él/ella)."}}, {"title": "How do I give opinions with reasons?", "html": "<p>Top marks need an <strong>opinion with a reason</strong>, not just a description:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"creo que\">creo que…</span></td><td>I think that…</td></tr>\n              <tr><td><span data-say=\"me parece que\">me parece que…</span></td><td>it seems to me that…</td></tr>\n              <tr><td><span data-say=\"porque\">porque</span></td><td>because</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Creo que es una familia feliz porque todos están sonriendo.\">Creo que es una familia feliz porque todos están sonriendo.</span> — <em>I think it’s a happy family because everyone is smiling.</em></p>", "check": {"question": "Which gives an opinion WITH a reason?", "options": ["Creo que es una familia feliz porque están sonriendo", "Es una familia", "Hay una familia muy feliz que sonríe mucho aquí siempre hoy", "Creo que es una familia feliz"], "answer": 0, "explain": "Only option A gives both an opinion (creo que) AND a reason (porque). C is longer but is only a description, never an opinion."}}, {"title": "Higher: role-play register and developing your answers", "html": "<p><span class=\"tier-h\">H</span> The role-play tests <strong>register</strong> — a formal register with a teacher or shop assistant, informal with a friend. In the unprepared conversation, <strong>develop</strong> every answer: add a reason, an opinion, and a second tense.</p>\n            <ul>\n              <li><span data-say=\"¿Podría repetir la pregunta, por favor?\">¿Podría repetir la pregunta, por favor?</span> — formal, if you need it repeated</li>\n              <li><span data-say=\"En el futuro, me gustaría visitar España porque quiero mejorar mi español.\">En el futuro, me gustaría visitar España porque quiero mejorar mi español.</span> <span class=\"tier-h\">H</span> — adds a future plan + a reason</li>\n              <li><span data-say=\"El año pasado, fui de vacaciones con mi familia y fue estupendo.\">El año pasado, fui de vacaciones con mi familia y fue estupendo.</span> <span class=\"tier-h\">H</span> — adds a past tense</li>\n            </ul>", "check": {"question": "What makes a Higher-tier answer stronger in the unprepared conversation?", "options": ["giving only one-word answers to save time", "adding a reason, an opinion and a second tense", "repeating the same sentence structure each time", "speaking as quickly as possible without pausing"], "answer": 1, "explain": "Developing an answer with a reason, an opinion and a second tense shows range — that is what the top band rewards."}}]}, "terms": {"enabled": true, "pairs": [{"term": "en la foto hay", "definition": "in the photo there is/are"}, {"term": "veo", "definition": "I see"}, {"term": "hay una persona que", "definition": "there is a person who"}, {"term": "está comiendo", "definition": "he/she is eating"}, {"term": "está jugando", "definition": "he/she is playing"}, {"term": "está leyendo", "definition": "he/she is reading"}, {"term": "creo que", "definition": "I think that"}, {"term": "me parece que", "definition": "it seems to me that"}, {"term": "porque", "definition": "because"}, {"term": "el juego de rol", "definition": "the role-play"}, {"term": "la conversación no preparada", "definition": "the unprepared conversation"}, {"term": "leer en voz alta", "definition": "to read aloud"}, {"term": "la preparación", "definition": "the preparation (time)"}, {"term": "quince minutos", "definition": "fifteen minutes"}, {"term": "la tarjeta con fotos", "definition": "the photo card"}, {"term": "el registro formal (H)", "definition": "formal register"}, {"term": "desarrollar la respuesta (H)", "definition": "to develop your answer"}, {"term": "la pronunciación", "definition": "pronunciation"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Voy a describir la foto.\" data-listen></span><br>Listen. What is the speaker about to do?", "options": ["Give an opinion about school", "Ask a question about the family", "Describe the photo", "Talk about last weekend"], "answer": 2, "explain": "‘voy a describir la foto’ = I’m going to describe the photo. The traps swap in an opinion, a question or a different time."}, {"question": "<span data-say=\"En la foto hay una familia que está comiendo.\" data-listen></span><br>Listen. What does the speaker say is happening?", "options": ["A family is eating and talking loudly", "A family is going to eat later", "A family ate lunch yesterday", "A family is eating"], "answer": 3, "explain": "‘está comiendo’ = present continuous, eating right now. There is no mention of talking loudly, and it is not future or past."}, {"question": "How should you pronounce the ‘g’ in ‘gente’?", "options": ["A throaty ‘h’ sound, like in ‘jamón’", "A hard ‘g’ sound, like in ‘gato’", "Completely silent, like the Spanish ‘h’", "A soft English ‘j’ sound, like in ‘jelly’"], "answer": 0, "explain": "Before e/i, Spanish ‘g’ is throaty like ‘j’ — gente, gimnasio. Before a/o/u it is hard, as in gato."}, {"question": "Which word contains a completely SILENT letter?", "options": ["gente", "hacer", "cabeza", "perro"], "answer": 1, "explain": "The ‘h’ in hacer is always silent. The others test different sound rules (throaty g, soft c/z, rolled rr)."}, {"question": "Complete: ‘Los chicos _____ en el parque.’ (playing, right now)", "options": ["juegan", "están jugar", "están jugando", "estás jugando"], "answer": 2, "explain": "Present continuous = estar + gerund: están jugando. ‘juegan’ is simple present; ‘están jugar’ wrongly uses the infinitive; ‘estás’ is the wrong subject."}, {"question": "Which correctly means ‘I see a young girl’?", "options": ["Veo una chica joven que sonríe mucho hoy", "Vea una chica joven", "Veo un chica joven", "Veo a una chica joven"], "answer": 3, "explain": "The personal ‘a’ is needed before a person: veo A una chica. Option A omits the personal ‘a’ despite being longer; B wrongly conjugates ver; C mismatches the article."}, {"question": "Which sentence gives a personal OPINION (not just a description)?", "options": ["Me parece que es una foto muy alegre", "Es una foto", "Hay una foto de una familia", "La foto muestra una cocina grande y moderna"], "answer": 0, "explain": "‘me parece que’ signals an opinion. The others only describe — D is longer but still just a description, the classic trap."}, {"question": "How long is the supervised preparation time before Paper 2 Speaking?", "options": ["5 minutes", "15 minutes", "30 minutes", "50 minutes, the same as the total marks"], "answer": 1, "explain": "You get 15 minutes to prepare. The last trap confuses the prep time with the total marks (50)."}, {"question": "In the role-play with a teacher or shop-assistant character, which register should you use?", "options": ["Exactly the same slang you use with friends", "No register at all — grammar doesn’t matter here", "A polite, formal register", "A random mix of formal and informal in one sentence"], "answer": 2, "explain": "Role-play characters in authority (teacher, shop assistant) need a formal register."}, {"question": "Which best describes Spanish vowel sounds compared to English?", "options": ["Vowels change sound depending on the word’s length", "Spanish vowels are always silent when unstressed", "Vowels are pronounced exactly like English vowels", "Each vowel has one pure, short sound"], "answer": 3, "explain": "Spanish has five pure vowel sounds that don’t change or blend like English diphthongs."}]}, "fib": {"enabled": true, "questions": [{"text": "En la foto [hay] dos personas. <span data-say=\"En la foto hay dos personas.\" data-listen>En la foto hay dos personas.</span>"}, {"text": "También [veo] un perro pequeño en el jardín. <span data-say=\"También veo un perro pequeño en el jardín.\" data-listen>También veo un perro pequeño en el jardín.</span>"}, {"text": "La familia está [comiendo] en el jardín. <span data-say=\"La familia está comiendo en el jardín.\" data-listen>La familia está comiendo en el jardín.</span>"}, {"text": "Los niños están [jugando] al fútbol. <span data-say=\"Los niños están jugando al fútbol.\" data-listen>Los niños están jugando al fútbol.</span>"}, {"text": "Creo que están felices [porque] están de vacaciones. <span data-say=\"Creo que están felices porque están de vacaciones.\" data-listen>Creo que están felices porque están de vacaciones.</span>"}, {"text": "Hay que leer el texto en voz [alta]. <span data-say=\"Hay que leer el texto en voz alta.\" data-listen>Hay que leer el texto en voz alta.</span>"}, {"text": "El chico está [leyendo] un libro en la foto. <span data-say=\"El chico está leyendo un libro en la foto.\" data-listen>El chico está leyendo un libro en la foto.</span>"}]}, "tf": {"enabled": true, "questions": [{"statement": "Paper 2 Speaking is worth 25% of the whole GCSE.", "answer": true, "explain": "50 marks out of the total GCSE = 25%."}, {"statement": "The photo card is worth more marks than the role-play.", "answer": true, "explain": "Photo card = 25 marks; role-play = 10 marks."}, {"statement": "In Castilian Spanish, ‘c’ before e/i is pronounced like an English hard ‘k’.", "answer": false, "explain": "It is pronounced like a soft ‘th’ sound, not a hard ‘k’."}, {"statement": "The letter ‘h’ on its own is always silent in Spanish.", "answer": true, "explain": "hola, hacer, hermano — the h is never pronounced on its own."}, {"statement": "‘está comiendo’ uses the present continuous tense.", "answer": true, "explain": "estar + gerund (comiendo) = present continuous."}, {"statement": "You get 15 minutes to prepare before Paper 2 Speaking.", "answer": true, "explain": "15 minutes of supervised preparation time."}, {"statement": "‘Me parece que’ can be used to introduce an opinion.", "answer": true, "explain": "me parece que = it seems to me that — a standard opinion phrase."}, {"statement": "The rolled ‘rr’ sound is pronounced exactly the same as a single ‘r’.", "answer": false, "explain": "‘rr’ is strongly rolled and clearly different from a single ‘r’, e.g. perro vs pero."}]}, "misc": {"enabled": true, "items": [{"myth": "El chico estoy comiendo.", "truth": "El chico <span data-say=\"está comiendo\">está comiendo</span>.", "check": {"question": "Why is ‘El chico estoy comiendo’ wrong?", "options": ["the verb must agree with ‘el chico’ → está, not estoy", "‘comiendo’ should be ‘comido’ instead", "you cannot use the present continuous tense to describe a photo at all", "‘el chico’ needs to become ‘los chicos’"], "answer": 0, "explain": "estar agrees with the subject: el chico (he) → está, not estoy (yo)."}}, {"myth": "En la foto es dos personas.", "truth": "En la foto <span data-say=\"hay dos personas\">hay dos personas</span>.", "check": {"question": "Why is ‘En la foto es dos personas’ wrong?", "options": ["‘dos’ should become ‘dos personas y’", "‘hay’ (there is/are) is needed, not ‘es’", "‘foto’ needs the article ‘el’, not ‘la’", "the sentence should start with ‘Veo’ instead"], "answer": 1, "explain": "‘hay’ is the impersonal verb for ‘there is/are’ used to describe a photo — ‘es’ does not work here."}}, {"myth": "Pronouncing cabeza with a hard English ‘k’ and a buzzing ‘z’.", "truth": "<span data-say=\"cabeza\">cabeza</span> pronounced with a soft Castilian ‘th’ sound for the c and z.", "check": {"question": "Which word uses the SAME soft sound rule as ‘cabeza’?", "options": ["gato", "hola", "cinco", "perro"], "answer": 2, "explain": "‘ci’ in cinco is soft, like the c/z in cabeza. gato has a hard g, hola has a silent h, perro tests rolled rr."}}, {"myth": "Veo un chica en la foto.", "truth": "Veo a una <span data-say=\"chica\">chica</span> en la foto.", "check": {"question": "What is missing from ‘Veo un chica’?", "options": ["an accent on the word ‘chica’", "the word ‘mucho’ needs to go somewhere before chica", "a comma after ‘veo’", "the personal ‘a’ and correct feminine article ‘una’"], "answer": 3, "explain": "You need the personal ‘a’ before a person (veo A) and the feminine article ‘una’, not ‘un’."}}, {"myth": "Me parece bien.", "truth": "Me parece bien <span data-say=\"porque todos están sonriendo\">porque todos están sonriendo</span>.", "check": {"question": "Why does ‘Me parece bien’ alone lose marks in the photo card?", "options": ["it gives an opinion but no reason (no ‘porque’)", "‘parece’ is spelt incorrectly in this sentence", "it should say ‘me parecen bien’ instead, every time", "it is in the wrong tense for a photo"], "answer": 0, "explain": "An opinion without a reason is incomplete — always follow it with ‘porque…’."}}]}, "tips": {"enabled": true, "items": [{"title": "Reading Aloud — the pronunciation checklist", "html": "Before you read, scan the text for the six sound rules: silent ‘h’, soft ‘c/z’, throaty ‘g/j’, ‘ñ’, rolled ‘rr’, and pure vowels. Read at a <strong>steady, natural pace</strong> — rushing causes more pronunciation slips than any single sound.<br>Practice line: <span data-say=\"El hombre hace ejercicio y juega con su perro cerca del gimnasio.\">El hombre hace ejercicio y juega con su perro cerca del gimnasio.</span>", "check": {"question": "What causes the most pronunciation slips when reading aloud?", "options": ["using the wrong preparation time before the exam", "reading too fast instead of at a steady pace", "choosing the wrong register for the task", "forgetting to give an opinion at the end"], "answer": 1, "explain": "Rushing is the biggest cause of pronunciation slips — read at a steady, natural pace."}}, {"title": "Photo Card — build a full-mark answer", "html": "Structure your answer in stages: describe with ‘hay’ / ‘veo’, add the action with the present continuous (está + gerund), then give an opinion (creo que…) with a reason (porque…) and a second detail.", "check": {"question": "What is the best structure for a full photo-card answer?", "options": ["opinion first, then never describe the photo at all, for the whole answer", "reason only, with no description or opinion given anywhere", "describe (hay/veo) → action → opinion (creo que) → reason (porque)", "present continuous only, repeated four times with no other content"], "answer": 2, "explain": "Description, action, opinion, reason — in that order — builds a complete, high-scoring answer."}}, {"title": "Role-play & unprepared conversation — Higher", "html": "In the unprepared conversation, always <strong>develop</strong> your answer: add a reason, an opinion, and a second tense (past or future) instead of a bare fact. <span class=\"tier-h\">H</span>", "check": {"question": "Which response would score highest at Higher tier?", "options": ["Fui de vacaciones el año pasado y fui de vacaciones otra vez el mes pasado", "Bien", "Fui de vacaciones el año pasado", "Fui de vacaciones el año pasado y fue estupendo porque hizo mucho sol"], "answer": 3, "explain": "Option D adds a past tense, an opinion (fue estupendo) and a reason (porque hizo mucho sol). Option A is just as long but repeats the same idea without developing it."}}]}, "exam": {"enabled": true, "questions": [{"question": "Practise reading this text aloud. Read it yourself first at a steady pace, then tap 🔊 to hear a model and self-mark your pronunciation against the checklist below.<br><span data-say=\"Los fines de semana, mi hermano hace ejercicio en el gimnasio y juega con nuestro perro en el parque. A veces le duele la cabeza porque hay mucha gente allí.\">Los fines de semana, mi hermano hace ejercicio en el gimnasio y juega con nuestro perro en el parque. A veces le duele la cabeza porque hay mucha gente allí.</span>", "marks": 5, "hint": "Say it once yourself before you listen to the model, then compare each sound rule in turn.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (Speaking: pronunciation)</h5><ul>\n                <li>Silent ‘h’ in <em>hermano</em> and <em>hace</em> — not pronounced <em>(1)</em>.</li>\n                <li>Soft ‘c’ in <em>cabeza</em> — a ‘th’ sound, not a hard ‘k’ or English ‘z’ <em>(1)</em>.</li>\n                <li>Throaty ‘g/j’ in <em>gimnasio</em>, <em>juega</em>, <em>gente</em> <em>(1)</em>.</li>\n                <li>Strongly rolled ‘rr’ in <em>perro</em> <em>(1)</em>.</li>\n                <li>Clear, pure vowels read at a steady pace, not rushed <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Self-assess honestly — tick a sound only if you actually produced it, not if you meant to.</li>\n            </ul></div>"}, {"question": "Imagine your photo card shows: a big kitchen; a mother cooking; a boy doing his homework at the table; a dog under the table. Describe the photo <strong>in Spanish</strong>, then give your opinion with a reason.", "marks": 5, "hint": "Start with En la foto hay… or Veo…, add está + -ando/-iendo for the action, then Creo que… porque… for your opinion and reason.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (Speaking: photo card content)</h5><ul>\n                <li>Description using ‘hay’ or ‘veo’ <em>(1)</em>.</li>\n                <li>A present-continuous verb (está + gerund) <em>(1)</em>.</li>\n                <li>A clear opinion (creo que… / me parece que…) <em>(1)</em>.</li>\n                <li>A reason for the opinion (porque…) <em>(1)</em>.</li>\n                <li>One further detail from the photo <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Tick a point only if you actually said it out loud, not just thought it.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'x-4-writing-and-translation-into-spanish', 'X.4 Writing and Translation into Spanish', '{"learn": {"enabled": true, "items": [{"title": "What does Paper 4 (Writing) look like?", "html": "<p>Paper 4 is a <strong>written</strong> exam — no listening or speaking here. It lasts <span data-say=\"una hora y diez minutos en el nivel Foundation\">1h10</span> at Foundation and <span data-say=\"una hora y quince minutos en el nivel Higher\">1h15</span> at Higher, and is worth <strong>50 marks</strong> — <strong>25%</strong> of the whole GCSE.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>Foundation Q1</td><td>5 short sentences about a photo (10)</td></tr>\n              <tr><td>Foundation Q2</td><td>~50 words to 5 bullet points (10)</td></tr>\n              <tr><td>Foundation Q3</td><td>5 short grammar tasks (5)</td></tr>\n              <tr><td>Foundation Q4</td><td>translation English→Spanish, min. 35 words (10)</td></tr>\n              <tr><td>Overlap question</td><td>~90 words to 3 bullets, choice of two (15)</td></tr>\n              <tr><td>Higher Q1</td><td>translation English→Spanish, min. 50 words (10)</td></tr>\n              <tr><td>Higher Q3</td><td>~150 words, respond to 2 bullets, choice of two (25)</td></tr>\n            </table>\n            <p>Every mark comes from the Spanish you write on the page, so accuracy and range matter more than raw length.</p>", "check": {"question": "How many marks is Paper 4 worth, and what percentage of the GCSE is that?", "options": ["50 marks — 25% of the GCSE", "60 marks — 30% of the GCSE, the biggest of the four papers", "50 marks — 20% of the GCSE, the same weight as every other paper", "40 marks — 25% of the GCSE, and it is marked entirely by a computer"], "answer": 0, "explain": "Paper 4 (Writing) is 50 marks and 25% of the GCSE — the same weighting as the other three papers, not more or less."}}, {"title": "Foundation Q1 — describing the photo", "html": "<p>Q1 asks for <strong>five short sentences</strong> about a photo, 2 marks each. Use these openers, then add a detail:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"Hay\">Hay…</span></td><td>there is / there are…</td><td><span data-say=\"En la foto\">En la foto…</span></td><td>in the photo…</td></tr>\n              <tr><td><span data-say=\"Se ve\">Se ve…</span></td><td>you can see…</td><td><span data-say=\"Al fondo\">Al fondo…</span></td><td>in the background…</td></tr>\n              <tr><td><span data-say=\"A la izquierda\">a la izquierda</span></td><td>on the left</td><td><span data-say=\"a la derecha\">a la derecha</span></td><td>on the right</td></tr>\n            </table>\n            <p>Model sentences: <span data-say=\"Hay dos personas en la foto y hace mucho sol.\">Hay dos personas en la foto y hace mucho sol.</span> <em>(There are two people in the photo and it is very sunny.)</em> — <span data-say=\"Al fondo, se ve un parque con muchos árboles.\">Al fondo, se ve un parque con muchos árboles.</span> <em>(In the background, you can see a park with lots of trees.)</em></p>", "check": {"question": "Which sentence best suits Q1 (describing a photo)?", "options": ["Hay dos personas en el parque.", "Ayer hice mis deberes en casa.", "Si tuviera más tiempo, viajaría mucho más.", "Aunque me gusta, prefiero hacer otra cosa."], "answer": 0, "explain": "‘Hay…’ + a simple present-tense observation is the openers examiners want for the photo task — not a past story or a conditional opinion."}}, {"title": "Answering every bullet point (Q2 and the overlap question)", "html": "<p>Q2 (~50 words) and the overlap question (~90 words) always give you <strong>bullet points</strong> — miss one and you cap your own mark, however good the Spanish is. Link your ideas with connectors instead of short, disconnected sentences:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"y\">y</span></td><td>and</td><td><span data-say=\"pero\">pero</span></td><td>but</td></tr>\n              <tr><td><span data-say=\"porque\">porque</span></td><td>because</td><td><span data-say=\"también\">también</span></td><td>also</td></tr>\n              <tr><td><span data-say=\"además\">además</span></td><td>furthermore</td><td><span data-say=\"sin embargo\">sin embargo</span></td><td>however</td></tr>\n            </table>\n            <p>Model sentences: <span data-say=\"Me gusta el colegio porque tengo muchos amigos, pero a veces hay demasiados deberes.\">Me gusta el colegio porque tengo muchos amigos, pero a veces hay demasiados deberes.</span> — <span data-say=\"Además, mis profesores son simpáticos y me ayudan mucho.\">Además, mis profesores son simpáticos y me ayudan mucho.</span></p>", "check": {"question": "A student answers only 3 of the 5 bullet points in Q2. What happens?", "options": ["Their mark is capped, even if the Spanish for those 3 points is excellent", "Nothing — only the quality of the Spanish is ever marked", "They automatically get half marks for the whole question no matter what they wrote", "The examiner chooses two extra bullet points for them"], "answer": 0, "explain": "Content marks require every bullet to be addressed; skipping bullets caps the mark regardless of language quality."}}, {"title": "Reaching the top band: opinions and tense variety", "html": "<p>Examiners reward <strong>range</strong>, not length. Aim for at least three tenses and always give an opinion with a reason, not just a fact:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>present</td><td><span data-say=\"Juego al fútbol todos los días.\">Juego al fútbol todos los días.</span></td></tr>\n              <tr><td>past (preterite)</td><td><span data-say=\"El año pasado gané un torneo local.\">El año pasado gané un torneo local.</span></td></tr>\n              <tr><td>future / conditional</td><td><span data-say=\"El año que viene voy a entrenar más y me gustaría ganar otra vez.\">El año que viene voy a entrenar más y me gustaría ganar otra vez.</span></td></tr>\n            </table>\n            <p>Opinion + reason: <span data-say=\"En mi opinión, el deporte es importante porque nos mantiene sanos y nos ayuda a hacer amigos.\">En mi opinión, el deporte es importante porque nos mantiene sanos y nos ayuda a hacer amigos.</span></p>", "check": {"question": "Which feature of an answer earns credit for range?", "options": ["Using present, past and future tenses across the answer", "Repeating the same present-tense sentence in different words", "Writing as many words as possible without any connectors", "Copying the bullet points exactly as they are printed"], "answer": 0, "explain": "Range comes from varied tenses, connectors and opinions — not from word count or repetition."}}, {"title": "Translating into Spanish — technique", "html": "<p>Translation tests accuracy, not creativity. Four things examiners check line by line:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>word order</td><td><span data-say=\"mi profesora de inglés\">mi profesora de inglés</span> — not “mi de inglés profesora”</td></tr>\n              <tr><td>agreement</td><td><span data-say=\"dos hermanas altas\">dos hermanas altas</span> — every adjective must agree</td></tr>\n              <tr><td>the right tense</td><td><span data-say=\"ayer hice mis deberes\">ayer hice mis deberes</span> — past, not present</td></tr>\n              <tr><td>accents</td><td><span data-say=\"fácil, según, jóvenes\">fácil / según / jóvenes</span> — a missing accent can lose the mark</td></tr>\n            </table>\n            <p>Work sentence by sentence, then read your Spanish back and check it sounds natural, not like a word-for-word crib.</p>", "check": {"question": "Why is “mi de inglés profesora” wrong for ‘my English teacher’?", "options": ["Spanish word order is different from English — the noun and its details must be reordered", "‘de inglés’ should always come before ‘mi’", "the sentence is missing the personal ‘a’, which every sentence about a person must include", "‘profesora’ needs a written accent on the final letter"], "answer": 0, "explain": "Spanish word order for ‘mi profesora de inglés’ places the noun before ‘de inglés’ — translating word-for-word gives the wrong order. The personal ‘a’ rule (option C) doesn''t apply here at all."}}, {"title": "Higher: planning the 150-word open response (Q3)", "html": "<p><span class=\"tier-h\">H</span> Q3 gives <strong>two questions</strong> — you choose <strong>one</strong> — and asks you to respond to <strong>two bullet points</strong> in about 150 words. Plan before you write:</p>\n            <ul>\n              <li>one idea + opinion + reason for EACH bullet point</li>\n              <li>at least one complex connector: <span data-say=\"aunque\">aunque</span>, <span data-say=\"sin embargo\">sin embargo</span>, <span data-say=\"a pesar de\">a pesar de</span> <span class=\"tier-h\">H</span></li>\n              <li>a genuine spread of tenses across the whole answer, not just one paragraph</li>\n            </ul>\n            <p>Model opener: <span data-say=\"Aunque me gusta mucho mi colegio, a veces hay demasiada presión con los exámenes.\">Aunque me gusta mucho mi colegio, a veces hay demasiada presión con los exámenes.</span> <span class=\"tier-h\">H</span></p>", "check": {"question": "At Higher tier, what must you do before starting Q3?", "options": ["Choose ONE of the two questions and plan an idea for each bullet point", "Answer both questions fully, one after the other, to maximise the marks available", "Write only in the present tense to avoid mistakes", "Copy the two bullet points as your first two sentences"], "answer": 0, "explain": "Q3 offers a choice of two questions — pick ONE, and plan an opinion + reason for each of its two bullet points. Attempting both wastes time and earns nothing extra."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Hay…", "definition": "there is / there are…"}, {"term": "En la foto…", "definition": "in the photo…"}, {"term": "pero", "definition": "but"}, {"term": "porque", "definition": "because"}, {"term": "también", "definition": "also"}, {"term": "además", "definition": "furthermore"}, {"term": "sin embargo", "definition": "however"}, {"term": "aunque", "definition": "although"}, {"term": "un mínimo de 35 palabras", "definition": "minimum 35 words (Foundation translation)"}, {"term": "un mínimo de 50 palabras (H)", "definition": "minimum 50 words (Higher translation)"}, {"term": "el borrador", "definition": "the draft / rough plan"}, {"term": "la traducción", "definition": "the translation"}, {"term": "contestar todos los puntos", "definition": "to answer every bullet point"}, {"term": "la variedad de tiempos verbales", "definition": "tense variety"}, {"term": "dar una opinión con una razón", "definition": "to give an opinion with a reason"}, {"term": "el orden de las palabras", "definition": "word order"}, {"term": "la concordancia de los adjetivos (H)", "definition": "adjective agreement"}, {"term": "elegir entre dos preguntas (H)", "definition": "to choose between two questions"}]}, "mcq": {"enabled": true, "questions": [{"question": "How many marks is the Foundation translation task (Q4, English→Spanish) worth?", "options": ["10 marks, for a minimum of 35 words", "15 marks, for a minimum of 50 words", "5 marks, for exactly ten words", "25 marks, for the longest answer on the paper"], "answer": 0, "explain": "Foundation Q4 (translation into Spanish) is 10 marks, minimum 35 words. Higher Q1 raises this to 50 words for the same 10 marks."}, {"question": "<span data-say=\"Voy a describir la foto: hay una familia en el parque.\" data-listen></span><br>Listen. What is the speaker about to do?", "options": ["Describe the photo", "Ask a question about the photo", "Translate the photo caption into English", "Give an opinion about something from yesterday"], "answer": 0, "explain": "‘voy a describir la foto’ = I’m going to describe the photo. The traps swap the task for a question, a translation or a past opinion."}, {"question": "<span data-say=\"En mi opinión, es importante hacer ejercicio porque es bueno para la salud.\" data-listen></span><br>Listen. What is being expressed?", "options": ["An opinion together with a reason", "A simple fact with no opinion given", "A question about staying healthy", "An instruction telling someone to stop exercising"], "answer": 0, "explain": "‘en mi opinión… porque…’ signals an opinion with a reason — exactly the top-band feature examiners are listening for."}, {"question": "Which sentence shows correct adjective agreement?", "options": ["<span data-say=\"Tengo dos hermanas altas.\">Tengo dos hermanas altas.</span>", "Tengo dos hermanas altas y bajo.", "Tengo dos hermano alta.", "Tengo dos hermana altos."], "answer": 0, "explain": "‘hermanas’ is feminine plural, so every adjective must also be feminine plural: altas. Option B adds a second adjective (bajo) that disagrees; the others mismatch gender or number somewhere."}, {"question": "Grammar task: ‘Ayer, mi hermano _____ al cine con sus amigos.’ Which verb form is correct?", "options": ["<span data-say=\"Ayer, mi hermano fue al cine con sus amigos.\">fue</span>", "va", "iba", "irá"], "answer": 0, "explain": "‘Ayer’ (yesterday) needs the preterite for a single completed action: fue (went). va=present, iba=imperfect, irá=future — all wrong tense for ‘ayer’."}, {"question": "Which sentence uses a connector to show contrast?", "options": ["<span data-say=\"Me gusta el fútbol, pero prefiero el baloncesto.\">Me gusta el fútbol, pero prefiero el baloncesto.</span>", "Me gusta el fútbol y también el baloncesto los fines de semana.", "Me gusta el fútbol porque es muy divertido.", "Me gusta mucho el fútbol todos los fines de semana."], "answer": 0, "explain": "‘pero’ = but, showing contrast. Option B is longer but only adds (‘y también’), it does not contrast; the others use a reason or no connector at all."}, {"question": "Translate: ‘my English teacher’ (a woman) into Spanish.", "options": ["<span data-say=\"mi profesora de inglés\">mi profesora de inglés</span>", "mi de inglés profesora", "mi profesora inglés de", "profesora mi de inglés"], "answer": 0, "explain": "Correct Spanish word order is article + noun + ‘de’ + language: mi profesora de inglés. The others jumble the same words into the wrong order."}, {"question": "In the Higher tier, how many marks is Q3 (the ~150-word open response) worth?", "options": ["<span data-say=\"Q3 vale veinticinco puntos, la pregunta más importante del examen Higher.\">25 marks — the single biggest question on the whole paper</span>", "15 marks — the same value as the overlap question students also answer", "10 marks, matching the translation question earlier in the paper", "50 marks — it is the entire Higher paper marked as one question"], "answer": 0, "explain": "Higher Q3 is worth 25 marks, more than any other single question on Paper 4 — it rewards range and accuracy over 150 words."}, {"question": "Which answer is most likely to reach the top band?", "options": ["One that uses three tenses, gives an opinion with a reason, and links ideas with connectors", "One that repeats similar present-tense sentences several times in slightly different words to reach the word count", "One that copies the bullet points word-for-word with no extra detail added", "One long sentence with no full stops, connectors or punctuation at all"], "answer": 0, "explain": "Top-band answers show range (tenses, connectors, opinions) and accuracy — not sheer length or repetition to hit a word count."}, {"question": "Grammar task: which sentence correctly uses the conditional ‘me gustaría’?", "options": ["<span data-say=\"Me gustaría viajar a España el año que viene.\">Me gustaría viajar a España el año que viene.</span>", "Me gusta viajaría a España el año que viene.", "Me gustaría viajo a España el año que viene.", "Gustaría me viajar a España el año que viene."], "answer": 0, "explain": "‘me gustaría’ + infinitive = I would like to. The others mix tenses incorrectly or put the pronoun in the wrong place."}]}, "fib": {"enabled": true, "questions": [{"text": "Hay dos personas en la [foto]. <span data-say=\"Hay dos personas en la foto.\" data-listen>Hay dos personas en la foto.</span>"}, {"text": "Me gusta el fútbol, [pero] prefiero el baloncesto. (contrast)"}, {"text": "Es importante hacer ejercicio [porque] es bueno para la salud. (reason)"}, {"text": "Ayer [fui] al cine con mis amigos. <span data-say=\"Ayer fui al cine con mis amigos.\" data-listen>Ayer fui al cine con mis amigos.</span>"}, {"text": "La traducción debe tener un mínimo de treinta y cinco [palabras]. (words)"}, {"text": "[Sin] embargo, prefiero estudiar en casa por la tarde. (however)"}, {"text": "El año que viene, [iré] a la universidad. (will go — future tense)"}]}, "tf": {"enabled": true, "questions": [{"statement": "Paper 4 (Writing) is worth 50 marks and 25% of the GCSE.", "answer": true, "explain": "50 marks, 25% of the total GCSE — the same weighting as the other three papers."}, {"statement": "At Foundation tier, Q4 is a translation into Spanish of a minimum of 35 words.", "answer": true, "explain": "Foundation Q4: translate English into Spanish, minimum 35 words, 10 marks."}, {"statement": "At Higher tier, the ~150-word open response (Q3) is the lowest-mark question on the paper.", "answer": false, "explain": "It is the highest — 25 marks, more than any other single question on Paper 4."}, {"statement": "Connectors like ‘sin embargo’ and ‘aunque’ help you reach the top band by linking ideas.", "answer": true, "explain": "Range marks reward connectors that link and contrast ideas, not just short separate sentences."}, {"statement": "For the top band, it is enough to use one tense correctly throughout your whole answer.", "answer": false, "explain": "Examiners reward tense VARIETY — present, past and future/conditional across the answer."}, {"statement": "In the photo-description task, ‘Hay…’ and ‘En la foto…’ are useful sentence starters.", "answer": true, "explain": "Both openers are natural, mark-scoring ways to begin a Q1 photo sentence."}, {"statement": "When translating into Spanish, adjectives do not need to agree with the noun they describe.", "answer": false, "explain": "Adjective agreement (gender and number) is one of the four things examiners check in every translation."}, {"statement": "You should answer every bullet point in the structured writing tasks, or your mark is capped.", "answer": true, "explain": "Missing a bullet point caps the content mark, however good the Spanish for the other bullets is."}]}, "misc": {"enabled": true, "items": [{"myth": "Escribí muchas frases sobre la foto, pero solo usé el presente.", "truth": "<span data-say=\"Escribí sobre la foto usando el presente, el pasado y el futuro para mostrar variedad de tiempos verbales.\">Escribí sobre la foto usando el presente, el pasado y el futuro para mostrar variedad de tiempos verbales.</span>", "check": {"question": "Why does only using the present tense lose marks?", "options": ["Examiners reward tense variety across the whole answer, not just accuracy", "The present tense is always marked wrong on Paper 4, so it must be avoided completely", "Photo sentences must never use the present tense", "Using one tense makes the Spanish ungrammatical"], "answer": 0, "explain": "The present tense itself is fine, but sticking to ONE tense throughout misses the range marks that reward variety."}}, {"myth": "Tengo dos hermanas alto.", "truth": "<span data-say=\"Tengo dos hermanas altas.\">Tengo dos hermanas altas.</span>", "check": {"question": "Why is ‘Tengo dos hermanas alto’ wrong?", "options": ["‘hermanas’ is feminine plural, so the adjective must also be feminine plural: altas", "‘tengo’ needs to change to ‘tiene’, because the subject has changed from ‘yo’ to ‘él’", "‘alto’ should always come before the noun it describes", "‘dos’ needs a written accent before a feminine noun"], "answer": 0, "explain": "Adjectives agree in gender AND number with the noun: hermanas (fem. pl.) needs altas, not the masculine singular alto. The subject is still ‘yo’ (tengo), so option B is a distraction."}}, {"myth": "En la traducción, traduje palabra por palabra sin cambiar el orden.", "truth": "<span data-say=\"En la traducción, cambié el orden de las palabras para que sonara natural en español.\">En la traducción, cambié el orden de las palabras para que sonara natural en español, por ejemplo ‘mi profesora de inglés’.</span>", "check": {"question": "What is wrong with translating word-for-word?", "options": ["Spanish word order is often different from English, so a literal translation sounds unnatural or is marked wrong", "Word-for-word translation is always the safest, highest-scoring method because it keeps every English word in place", "Examiners only check spelling, never word order", "Word order does not matter in Spanish sentences"], "answer": 0, "explain": "A literal, word-for-word translation frequently produces the wrong Spanish word order and loses accuracy marks."}}, {"myth": "En mi respuesta de noventa palabras solo contesté dos de los tres puntos.", "truth": "<span data-say=\"En mi respuesta de noventa palabras contesté los tres puntos con el mismo nivel de detalle.\">En mi respuesta de noventa palabras contesté los tres puntos con el mismo nivel de detalle.</span>", "check": {"question": "What happens if a student only answers two of three bullet points?", "options": ["Their content mark is capped, even if the Spanish they did write is excellent", "Nothing changes, because only grammar accuracy is ever marked on this whole paper", "The examiner gives full marks for the two points they did answer and ignores the rest", "They are automatically awarded half marks for the whole task"], "answer": 0, "explain": "Content marks require every bullet point to be addressed — skipping one caps the mark regardless of language quality."}}, {"myth": "Escribí ‘me gusta el fútbol y me gusta el fútbol y me gusta el fútbol’ para llegar a las palabras.", "truth": "<span data-say=\"Escribí opiniones distintas con razones y conectores para llegar a las palabras con contenido de calidad.\">Escribí opiniones distintas con razones y conectores para llegar a las palabras con contenido de calidad.</span>", "check": {"question": "Why does repeating the same sentence to hit the word count fail?", "options": ["Marks reward the QUALITY and range of content, not simply reaching a word count", "The word count is only a suggestion and does not really need to be reached at all", "Repetition is grammatically incorrect in Spanish", "Examiners cannot read repeated sentences at all"], "answer": 0, "explain": "Reaching the word count with repeated, low-content sentences earns no extra marks — quality, range and addressing the bullets is what counts."}}]}, "tips": {"enabled": true, "items": [{"title": "Foundation Q1 &amp; Q2 — photo and bullet points", "html": "Q1: five short sentences using ‘Hay…’ / ‘En la foto…’ plus a detail, 2 marks each. Q2: ~50 words hitting all five bullet points, linked with ‘y’, ‘pero’, ‘porque’, ‘también’ so it reads as connected Spanish, not a list.", "check": {"question": "What is the biggest way to lose marks on Q2?", "options": ["Leaving one of the bullet points unanswered", "Using the connector ‘porque’ more than once", "Writing slightly more than 50 words", "Starting a sentence with ‘Hay’"], "answer": 0, "explain": "Every bullet point must be addressed — missing even one caps the content mark."}}, {"title": "Translation into Spanish — Q4 / Higher Q1", "html": "Translate sentence by sentence: get the tense right first (present/past/future), then check word order (mi profesora de inglés) and that every adjective agrees. Read the Spanish back — if it doesn’t sound natural, the word order is probably wrong.", "check": {"question": "What is the first thing to check when translating a sentence into Spanish?", "options": ["That you have used the correct tense for that sentence", "That every word has exactly the same number of letters as English", "That you have written the longest possible sentence", "That you have used the present tense throughout"], "answer": 0, "explain": "Tense comes first — a perfectly-spelled sentence in the wrong tense still loses the mark."}}, {"title": "Higher Q3 — the 150-word open response", "html": "Choose ONE of the two questions, then plan an opinion + reason for each of the two bullet points before you write. Combine a problem, an opinion and a future plan: <span data-say=\"Aunque me gusta mi colegio, a veces hay demasiada presión, así que voy a organizar mejor mi tiempo.\">‘Aunque me gusta mi colegio, a veces hay demasiada presión, así que voy a organizar mejor mi tiempo.’</span> Add ‘sin embargo’ or ‘a pesar de’ for extra range.", "check": {"question": "Which answer is closest to reaching the top band for Higher Q3?", "options": ["Aunque me gusta mi colegio, a veces hay demasiada presión, así que voy a organizar mejor mi tiempo", "Me gusta mi colegio y me gusta mi colegio y me gusta mucho mi colegio todos los días sin parar nunca", "Mi colegio", "Fui al colegio"], "answer": 0, "explain": "It links a contrast connector, an opinion, a reason and a future plan — range and accuracy, not just length."}}]}, "exam": {"enabled": true, "questions": [{"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I have two brothers.<br>(b) My father is very tall.<br>(c) We usually have dinner at eight o''clock.<br>(d) Yesterday I did my homework at home.<br>(e) In the future, I would like to travel to Spain.", "marks": 10, "hint": "Check the verb AND the tense in every sentence: (a)–(c) are present, (d) is a completed past action (preterite), (e) needs ‘me gustaría’ + infinitive.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 10 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Tengo dos hermanos. <em>(2 — 1 for verb/tense, 1 for word order &amp; agreement)</em></li>\n                <li><strong>(b)</strong> Mi padre es muy alto. <em>(2)</em></li>\n                <li><strong>(c)</strong> Normalmente cenamos a las ocho. <em>(2)</em></li>\n                <li><strong>(d)</strong> Ayer hice mis deberes en casa. <em>(2)</em></li>\n                <li><strong>(e)</strong> En el futuro, me gustaría viajar a España. <em>(2)</em></li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors if the word is still recognisable. Each sentence must use the correct tense to earn the verb mark.</li>\n            </ul></div>"}, {"question": "Escribe unas <strong>90 palabras</strong> sobre tu vida en el colegio. Menciona:<br>• tus asignaturas favoritas y por qué<br>• un problema que tuviste en el colegio y cómo lo resolviste<br>• tus planes para el año que viene", "marks": 15, "hint": "Address all three bullets. Use at least three tenses (present, past and future), one opinion with a reason, and connectors like porque, pero, sin embargo.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 15 marks (Content / Range / Accuracy)</h5><ul>\n                <li><strong>Content (6):</strong> all three bullet points addressed with real detail, 2 marks each.</li>\n                <li><strong>Range (5):</strong> three or more tenses used (2); two or more connectors used (2); an opinion with a reason given (1).</li>\n                <li><strong>Accuracy (4):</strong> verbs correctly conjugated for tense/subject (2); adjective agreement and spelling/accents mostly correct (2).</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>A student who addresses all bullets but stays in one tense cannot access full Range marks. Minor spelling slips that don''t obscure meaning are not heavily penalised.</li>\n            </ul></div>"}]}}'::jsonb)
